Param(
  [string]$SrcRoot = 'D:\fork',
  [string]$DstRoot = 'D:\envapt-pr'
)

$files = @(
  # envapt core
  'envapt\src\core\EnvapterBase.ts',
  'envapt\src\core\AdvancedMethods.ts',
  'envapt\src\nez-env.ts',
  'envapt\tsconfig.json',
  'envapt\vitest.config.ts',

  # tests
  'envapt\tests\11-nezlephant.test.ts',
  'envapt\tests\12-nezlephant-advanced.test.ts',
  'envapt\tests\setup-env.ts',
  'envapt\tests\secrets\discord-token.txt',

  # superimg plugin
  'envapt-superimg\src\index.ts',
  'envapt-superimg\src\verifyOC8.ts',
  'envapt-superimg\src\verifyOC8.cjs',
  'envapt-superimg\src\oc8.cjs',
  'envapt-superimg\src\__test__\verify-oc8.cjs',
  'envapt-superimg\src\__test__\oc8-roundtrip.cjs',
  'envapt-superimg\package.json',
  'envapt-superimg\tsconfig.json',

  # nezlephant
  'envapt-nezlephant\src\index.ts',
  'nezlephant\src\index.js',

  # scripts
  'scripts\bootstrap-and-test.ps1',
  'scripts\bootstrap-and-test.js',
  'scripts\link-local.ps1',
  'pr-body.md',
  '.gitignore'
)

foreach ($rel in $files) {
  $src = Join-Path $SrcRoot $rel
  $dst = Join-Path $DstRoot $rel
  if (-not (Test-Path $src)) { Write-Host "MISSING: $src" -ForegroundColor Yellow; continue }
  $dir = Split-Path $dst -Parent
  if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
  Copy-Item -Path $src -Destination $dst -Force
  Write-Host "Copied: $rel"
}

Write-Host "Done. Verify D:\envapt-pr contains the copied files."